import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"AI 伺服器 PCB 深度研究","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/PCB研究/AI伺服器PCB深度研究.md","filePath":"Deep32Q知識庫/產業洞察/PCB研究/AI伺服器PCB深度研究.md"}'),r={name:"Deep32Q知識庫/產業洞察/PCB研究/AI伺服器PCB深度研究.md"};function s(d,t,i,g,o,f){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="ai-伺服器-pcb-深度研究" tabindex="-1">AI 伺服器 PCB 深度研究 <a class="header-anchor" href="#ai-伺服器-pcb-深度研究" aria-label="Permalink to &quot;AI 伺服器 PCB 深度研究&quot;">​</a></h1><p><strong>更新日期：2026-05-13</strong></p><hr><h2 id="_1-ai-伺服器對-pcb-的需求本質" tabindex="-1">1. AI 伺服器對 PCB 的需求本質 <a class="header-anchor" href="#_1-ai-伺服器對-pcb-的需求本質" aria-label="Permalink to &quot;1. AI 伺服器對 PCB 的需求本質&quot;">​</a></h2><h3 id="ai-伺服器-vs-傳統伺服器-pcb-差異" tabindex="-1">AI 伺服器 vs 傳統伺服器 PCB 差異 <a class="header-anchor" href="#ai-伺服器-vs-傳統伺服器-pcb-差異" aria-label="Permalink to &quot;AI 伺服器 vs 傳統伺服器 PCB 差異&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">傳統伺服器</th><th style="text-align:left;">AI 伺服器</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>層數</strong></td><td style="text-align:left;">12–16 層</td><td style="text-align:left;">20–36 層（GB200 UBB 高達 30+ 層）</td></tr><tr><td style="text-align:left;"><strong>板材</strong></td><td style="text-align:left;">FR-4（一般損耗）</td><td style="text-align:left;">Ultra Low Loss (M7/IT-988GSE) / M8 等級</td></tr><tr><td style="text-align:left;"><strong>銅厚</strong></td><td style="text-align:left;">1–2 oz</td><td style="text-align:left;">&gt;3oz 厚銅（大電流供電需求）</td></tr><tr><td style="text-align:left;"><strong>背板尺寸</strong></td><td style="text-align:left;">~600×400mm</td><td style="text-align:left;">800×600mm 以上（GB200 Superchip）</td></tr><tr><td style="text-align:left;"><strong>HDI 技術</strong></td><td style="text-align:left;">標準盲埋孔</td><td style="text-align:left;">Any-Layer HDI、微孔 &lt;50μm</td></tr><tr><td style="text-align:left;"><strong>單台 PCB 價值</strong></td><td style="text-align:left;">~$2,000–5,000</td><td style="text-align:left;">~$15,000–30,000（含 UBB+OAM+背板）</td></tr></tbody></table><h3 id="關鍵技術挑戰" tabindex="-1">關鍵技術挑戰 <a class="header-anchor" href="#關鍵技術挑戰" aria-label="Permalink to &quot;關鍵技術挑戰&quot;">​</a></h3><ol><li><strong>訊號完整性</strong>：800G/1.6T 傳輸速率下，Ultra Low Loss CCL（Df &lt;0.002）為必要</li><li><strong>散熱管理</strong>：GB200 Superchip 功耗達 1,200W，PCB 散熱設計關鍵</li><li><strong>供電網路</strong>：&gt;3oz 厚銅、多層電源分配（PDN）設計</li><li><strong>尺寸與翹曲</strong>：大尺寸背板（800×600mm）的翹曲控制</li></ol><hr><h2 id="_2-nvidia-平台路線圖與-pcb-價值" tabindex="-1">2. NVIDIA 平台路線圖與 PCB 價值 <a class="header-anchor" href="#_2-nvidia-平台路線圖與-pcb-價值" aria-label="Permalink to &quot;2. NVIDIA 平台路線圖與 PCB 價值&quot;">​</a></h2><h3 id="各世代平台-pcb-規格與價值量變化" tabindex="-1">各世代平台 PCB 規格與價值量變化 <a class="header-anchor" href="#各世代平台-pcb-規格與價值量變化" aria-label="Permalink to &quot;各世代平台 PCB 規格與價值量變化&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">NVIDIA 平台</th><th style="text-align:left;">產品形態</th><th style="text-align:left;">層數</th><th style="text-align:left;">PCB 類型</th><th style="text-align:left;">單板價值量</th><th style="text-align:left;">台廠供應商</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>H100</strong></td><td style="text-align:left;">SXM5/OAM</td><td style="text-align:left;">20–28 層</td><td style="text-align:left;">UBB + OAM + 背板</td><td style="text-align:left;">~$15,000–20,000</td><td style="text-align:left;">金像電、健鼎</td></tr><tr><td style="text-align:left;"><strong>B200/GB200</strong></td><td style="text-align:left;">Superchip (CPU+GPU)</td><td style="text-align:left;">28–36 層</td><td style="text-align:left;">UBB + OAM + NVL72 背板</td><td style="text-align:left;">~$30,000–50,000</td><td style="text-align:left;">金像電、健鼎、博智</td></tr><tr><td style="text-align:left;"><strong>Rubin (B300)</strong></td><td style="text-align:left;">下一代 AI 加速卡</td><td style="text-align:left;">&gt;36 層</td><td style="text-align:left;">更高密度 UBB + OAM</td><td style="text-align:left;">預估再提升 50%+</td><td style="text-align:left;">待驗證台廠名單</td></tr></tbody></table><h3 id="nvidia-認證壁壘" tabindex="-1">NVIDIA 認證壁壘 <a class="header-anchor" href="#nvidia-認證壁壘" aria-label="Permalink to &quot;NVIDIA 認證壁壘&quot;">​</a></h3><ul><li><strong>認證週期</strong>：3 年以上（從設計到量產）</li><li><strong>核心供應商</strong>：金像電 (2368) 為全球最大 AI 伺服器板供應商</li><li><strong>AI UBB 市佔</strong>：金像電約 40%，2026 年預估提升至 50–70%</li><li><strong>美系 CSP 市佔</strong>：金像電從 2025 年 40–45% → 2026 年 &gt;50%</li></ul><hr><h2 id="_3-核心台廠分析" tabindex="-1">3. 核心台廠分析 <a class="header-anchor" href="#_3-核心台廠分析" aria-label="Permalink to &quot;3. 核心台廠分析&quot;">​</a></h2><h3 id="🔥-金像電-2368-—-ai-伺服器板全球龍頭" tabindex="-1">🔥 金像電 (2368) — AI 伺服器板全球龍頭 <a class="header-anchor" href="#🔥-金像電-2368-—-ai-伺服器板全球龍頭" aria-label="Permalink to &quot;🔥 金像電 (2368) — AI 伺服器板全球龍頭&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全球伺服器 PCB 市佔</strong></td><td style="text-align:left;">&gt;20%（全球第一）</td></tr><tr><td style="text-align:left;"><strong>AI UBB 市佔</strong></td><td style="text-align:left;">~40%（2025），預估 2026 年 50–70%</td></tr><tr><td style="text-align:left;"><strong>AI 營收佔比</strong></td><td style="text-align:left;">2023: ~20% → 2024: 20–30% → <strong>2026: ~50%</strong></td></tr><tr><td style="text-align:left;"><strong>2025 全年營收</strong></td><td style="text-align:left;">NT$600–1,671B（法人預估區間）</td></tr><tr><td style="text-align:left;"><strong>2025 Q3 單季</strong></td><td style="text-align:left;">NT$176.4B（創歷史新高）</td></tr><tr><td style="text-align:left;"><strong>2026 Q1 單季</strong></td><td style="text-align:left;">NT$193.1–193.4B（再創新高）</td></tr><tr><td style="text-align:left;"><strong>2026 全年預估</strong></td><td style="text-align:left;">NT$1,671B，EPS $35.29–38.40</td></tr><tr><td style="text-align:left;"><strong>主要客戶</strong></td><td style="text-align:left;">NVIDIA、AMD、Intel、美系 CSP（AWS/Google/Meta）</td></tr><tr><td style="text-align:left;"><strong>關鍵專案</strong></td><td style="text-align:left;">AWS Trainium 3、Google TPU 8、Meta MTIA</td></tr><tr><td style="text-align:left;"><strong>2026 亮點</strong></td><td style="text-align:left;">AI 佔比近 50%，伺服器業務佔總營收 80%</td></tr></tbody></table><p><strong>來源：CTEE 經濟日報 (2026/04), sinotrade.com</strong></p><h3 id="健鼎-3044-—-ai-轉型關鍵供應商" tabindex="-1">健鼎 (3044) — AI 轉型關鍵供應商 <a class="header-anchor" href="#健鼎-3044-—-ai-轉型關鍵供應商" aria-label="Permalink to &quot;健鼎 (3044) — AI 轉型關鍵供應商&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>2025 全年營收</strong></td><td style="text-align:left;">NT$734B（+11.5% YoY，創新高）</td></tr><tr><td style="text-align:left;"><strong>2026 Q1 單季</strong></td><td style="text-align:left;">NT$209.6B（+10.5% QoQ, +22.4% YoY）</td></tr><tr><td style="text-align:left;"><strong>2026 全年預估</strong></td><td style="text-align:left;">NT$840B，伺服器+記憶體雙主軸驅動</td></tr><tr><td style="text-align:left;"><strong>高階 HDI 佔比</strong></td><td style="text-align:left;">2026 Q1: 37.3%（高檔維持）</td></tr><tr><td style="text-align:left;"><strong>伺服器應用佔比</strong></td><td style="text-align:left;">2024 Q4: 33.6%（各項產品之首）</td></tr><tr><td style="text-align:left;"><strong>產能佈局</strong></td><td style="text-align:left;">越南周德新廠 2026 Q1 試產，月貢獻 NT$2–3B</td></tr><tr><td style="text-align:left;"><strong>主要產品</strong></td><td style="text-align:left;">伺服器主機板、多層高速板、記憶體用板、網通交換器</td></tr></tbody></table><p><strong>來源：CTEE 經濟日報 (2026/01, 2026/05), cnyes.com</strong></p><h3 id="博智-8155-—-利基型-ai-高層板" tabindex="-1">博智 (8155) — 利基型 AI 高層板 <a class="header-anchor" href="#博智-8155-—-利基型-ai-高層板" aria-label="Permalink to &quot;博智 (8155) — 利基型 AI 高層板&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>產品定位</strong></td><td style="text-align:left;">利基型 AI 高層板、特殊應用板</td></tr><tr><td style="text-align:left;"><strong>2026 營運</strong></td><td style="text-align:left;">法人預期動能強勁，AI 相關產品佔比持續提升</td></tr><tr><td style="text-align:left;"><strong>客戶群</strong></td><td style="text-align:left;">美系雲端供應商、AI ASIC 設計公司</td></tr><tr><td style="text-align:left;"><strong>技術優勢</strong></td><td style="text-align:left;">高層數（20+ 層）快速打樣與小批量生產能力</td></tr><tr><td style="text-align:left;"><strong>2026 亮點</strong></td><td style="text-align:left;">新客戶認證通過，AI 專案貢獻增加</td></tr></tbody></table><p><em>註：博智具體營收數據待查證，以上為產業定位分析。</em></p><hr><h2 id="_4-競爭格局" tabindex="-1">4. 競爭格局 <a class="header-anchor" href="#_4-競爭格局" aria-label="Permalink to &quot;4. 競爭格局&quot;">​</a></h2><h3 id="全球-ai-伺服器-pcb-供應商盤點" tabindex="-1">全球 AI 伺服器 PCB 供應商盤點 <a class="header-anchor" href="#全球-ai-伺服器-pcb-供應商盤點" aria-label="Permalink to &quot;全球 AI 伺服器 PCB 供應商盤點&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">類別</th><th style="text-align:left;">公司</th><th style="text-align:left;">國家</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>台廠</strong></td><td style="text-align:left;">金像電 (2368)</td><td style="text-align:left;">🇹🇼</td><td style="text-align:left;">全球最大，NVIDIA/AMD 認證</td></tr><tr><td style="text-align:left;"><strong>台廠</strong></td><td style="text-align:left;">健鼎 (3044)</td><td style="text-align:left;">🇹🇼</td><td style="text-align:left;">傳統伺服器龍頭，AI 轉型中</td></tr><tr><td style="text-align:left;"><strong>台廠</strong></td><td style="text-align:left;">博智 (8155)</td><td style="text-align:left;">🇹🇼</td><td style="text-align:left;">利基型高層板</td></tr><tr><td style="text-align:left;"><strong>日廠</strong></td><td style="text-align:left;">Ibiden (4062)</td><td style="text-align:left;">🇯🇵</td><td style="text-align:left;">載板龍頭，部分伺服器板</td></tr><tr><td style="text-align:left;"><strong>陸廠</strong></td><td style="text-align:left;">深南電 (002916)</td><td style="text-align:left;">🇨🇳</td><td style="text-align:left;">大陸伺服器板龍頭，快速追趕</td></tr><tr><td style="text-align:left;"><strong>陸廠</strong></td><td style="text-align:left;">景旺電子 (603228)</td><td style="text-align:left;">🇨🇳</td><td style="text-align:left;">多層板，部分 AI 專案</td></tr><tr><td style="text-align:left;"><strong>陸廠</strong></td><td style="text-align:left;">沪电股份 (002463)</td><td style="text-align:left;">🇨🇳</td><td style="text-align:left;">網通+伺服器板，成本優勢</td></tr></tbody></table><h3 id="台廠-vs-日廠-vs-陸廠競爭態勢" tabindex="-1">台廠 vs 日廠 vs 陸廠競爭態勢 <a class="header-anchor" href="#台廠-vs-日廠-vs-陸廠競爭態勢" aria-label="Permalink to &quot;台廠 vs 日廠 vs 陸廠競爭態勢&quot;">​</a></h3><ul><li><strong>台廠優勢</strong>：完整產業聚落、快速量產能力、NVIDIA 認證壁壘</li><li><strong>日廠優勢</strong>：Ibiden 載板技術領先、材料整合能力強</li><li><strong>陸廠挑戰</strong>：成本優勢明顯，但高階 AI 伺服器板認證週期長、技術差距仍在</li><li><strong>關鍵壁壘</strong>：NVIDIA 3 年以上認證期，新進入者難以短期取代現有台廠</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>CTEE 經濟日報</strong> (2026/04): 金像電 2025 營收預估 NT$600–1,671B, AI UBB 市佔 ~40%</li><li><strong>CTEE</strong> (2026/01): 健鼎 2025 營收 NT$734B, 2026 預估 NT$840B</li><li><strong>sinotrade.com</strong> (2026/05): 金像電 AI 佔比 2026 年 ~50%, 伺服器業務 80%</li><li><strong>digitimes</strong> (2026/05): AI 伺服器 PCB 市場 US$12–15B (2026), +28% YoY</li><li><strong>Prismark</strong> (2025): 全球 PCB 產值 US$103.6B, AI 佔比 &gt;25% (2026)</li><li><strong>TPCA-IEK</strong> (2026/05): 台灣 PCB 產值 NT$1.38–1.5T (2026), +8.7% YoY</li></ol>',34)])])}const h=e(r,[["render",s]]);export{y as __pageData,h as default};
